from flask import Flask, render_template_string
import requests

app = Flask(__name__)

PI_IP = '10.52.73.105'  # IP du Raspberry Pi (meme que PC_IP dans robot_agri_11.py)

HTML = """
<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <title>Test Buzzer</title>
  <style>
    body { display:flex; justify-content:center; align-items:center; height:100vh; background:#1a1a2e; margin:0; }
    button {
      padding: 20px 50px;
      font-size: 22px;
      background: #e94560;
      color: white;
      border: none;
      border-radius: 12px;
      cursor: pointer;
    }
    button:hover { background: #c73652; }
    #msg { color: white; margin-top: 20px; font-family: sans-serif; font-size: 16px; text-align:center; }
  </style>
</head>
<body>
  <div>
    <button onclick="lancerBuzzer()">🔔 Activer le Buzzer</button>
    <p id="msg"></p>
  </div>
  <script>
    function lancerBuzzer() {
      document.getElementById('msg').innerText = "Envoi en cours...";
      fetch('/lancer_buzzer')
        .then(r => r.text())
        .then(() => document.getElementById('msg').innerText = "✅ Buzzer activé !")
        .catch(() => document.getElementById('msg').innerText = "❌ Erreur de connexion");
    }
  </script>
</body>
</html>
"""

@app.route('/')
def index():
    return render_template_string(HTML)

@app.route('/lancer_buzzer')
def lancer_buzzer():
    try:
        requests.get(f'http://{PI_IP}:6000/buzzer', timeout=3)
        return "OK"
    except Exception as e:
        return f"Erreur : {e}", 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5001, debug=True)

